class Solution {
    public boolean hasAlternatingBits(int n) {
        int prevBit = -1;
        while (n > 0) {
            int currBit = n & 1;
            if (prevBit != -1 && currBit == prevBit) {
                return false;
            }
            prevBit = currBit;
            n >>= 1;
        }
        return true;
    }
}
